import{g as e,o as s}from"./chunks/theme.C9g6HaIV.js";import{c as o,Q as a,j as r,m as n}from"./chunks/framework.BPKcPtvA.js";const i="/videos/video-bulk-invite.webm",v=JSON.parse('{"title":"Users","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/users.md","filePath":"guide/portal/users.md","lastUpdated":1778912818000}'),d={name:"guide/portal/users.md"};function l(c,t,g,u,h,p){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h1><p>The <strong>Users</strong> page is where you manage everyone with access to your customer&#39;s portal and tenants. The model is two-layer: users exist at the <strong>customer level</strong>, and you then <strong>assign them to tenants</strong> with a role.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p><img src="'+e+'" alt="Portal Users page with expanded row" class="light-only"><img src="'+s+'" alt="Portal Users page with expanded row" class="dark-only"></p><video controls preload="metadata"><source src="'+i+'" type="video/webm"></video><p>A short introduction at the top — &quot;Invite users at customer level, then assign them to tenants.&quot; Below that, a paginated table with expandable rows. Toolbar with <strong>Bulk Assign</strong> and <strong>Invite Users</strong> buttons (if you have <code>manage_users</code>).</p><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Expand</strong></td><td>Toggle the detail row.</td></tr><tr><td><strong>Name</strong></td><td></td></tr><tr><td><strong>Email</strong></td><td></td></tr><tr><td><strong>Portal Role</strong></td><td>Owner / Admin / Member. Editable as a dropdown if you have <code>manage_users</code>.</td></tr><tr><td><strong>Status</strong></td><td>Active / Invited / Suspended.</td></tr><tr><td><strong>Tenants</strong></td><td>Count of assigned tenants.</td></tr><tr><td><strong>Instances</strong></td><td>Count of provisioned instances.</td></tr><tr><td><strong>Identity</strong></td><td>Internal / External badge.</td></tr><tr><td><strong>MFA</strong></td><td>Enabled / disabled.</td></tr><tr><td><strong>Actions</strong></td><td>Suspend / Reactivate on hover.</td></tr></tbody></table><h2 id="search-and-filters" tabindex="-1">Search and filters <a class="header-anchor" href="#search-and-filters" aria-label="Permalink to &quot;Search and filters&quot;">​</a></h2><p>The search field is <strong>token-aware</strong>. Type free text to match name or email, or use tokens:</p><ul><li><code>status:active</code>, <code>status:invited</code>, <code>status:suspended</code></li><li><code>role:owner</code>, <code>role:admin</code>, <code>role:member</code></li><li>Assignment state — <code>assigned</code>, <code>unassigned</code></li><li>Identity — <code>internal</code>, <code>external</code></li><li>MFA — <code>mfa:on</code>, <code>mfa:off</code></li></ul><p>Custom user attributes that your organisation has enabled appear as additional filters.</p><h2 id="expanded-row" tabindex="-1">Expanded row <a class="header-anchor" href="#expanded-row" aria-label="Permalink to &quot;Expanded row&quot;">​</a></h2><p>Click the chevron on a user row to expand:</p><p><strong>Summary header</strong> — Invited At, Last Login, Profile Completed flag, IDP User ID.</p><p><strong>Full details</strong> — Invited By, Created, Updated, Profile Cached, all custom attributes, External Customer / Org ID.</p><p><strong>Tenant Assignments sub-table</strong> — every tenant this user is assigned to, with role, status, and the instance the tenant lives on. You can change a user&#39;s role inside a tenant from the role dropdown here.</p><h2 id="inviting-users" tabindex="-1">Inviting users <a class="header-anchor" href="#inviting-users" aria-label="Permalink to &quot;Inviting users&quot;">​</a></h2><p>Click <strong>Invite Users</strong>. The bulk modal accepts pasted emails or an Excel upload.</p><ol><li><strong>Compose</strong> — paste emails (one per line) or upload a spreadsheet.</li><li><strong>Review</strong> — the modal shows what will happen for each email: <ul><li><strong>Already in customer</strong> — skipped.</li><li><strong>In system, not in customer</strong> — granted access (warning icon).</li><li><strong>New</strong> — invited.</li></ul></li><li><strong>Roles &amp; details</strong> — set the portal role per invitee.</li><li><strong>Send invites</strong>. The result screen lists successes and failures.</li></ol><h2 id="bulk-assigning-existing-users" tabindex="-1">Bulk assigning existing users <a class="header-anchor" href="#bulk-assigning-existing-users" aria-label="Permalink to &quot;Bulk assigning existing users&quot;">​</a></h2><p>Click <strong>Bulk Assign</strong> to assign customer users to a tenant at once.</p><ol><li>Pick the <strong>tenant</strong>.</li><li>Search and select the <strong>users</strong> to assign.</li><li>Pick a <strong>role</strong> for each (Tenant User / Tenant Admin).</li><li>Assign.</li></ol><h2 id="per-user-actions" tabindex="-1">Per-user actions <a class="header-anchor" href="#per-user-actions" aria-label="Permalink to &quot;Per-user actions&quot;">​</a></h2><ul><li><strong>Suspend / Reactivate</strong> — hover the row to reveal the action.</li><li><strong>Change Portal Role</strong> — use the dropdown in the Portal Role column.</li><li><strong>Resend Invite</strong> — only for users still in <code>invited</code> status.</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Requires</th></tr></thead><tbody><tr><td>Viewing this page</td><td><code>view_users</code></td></tr><tr><td>Inviting, suspending, assigning, role changes</td><td><code>manage_users</code></td></tr></tbody></table><p>Without <code>manage_users</code>, the table is read-only — the toolbar buttons and row actions do not appear.</p>',28)])])}const f=o(d,[["render",l]]);export{v as __pageData,f as default};
